import { Request, Response, NextFunction } from 'express';
import { BaseError } from '../exceptions/base-error';
import { logger } from '../utils/logger';

export const errorHandler = (err: BaseError, req: Request, res: Response, next: NextFunction) => {
  logger.error({ message: err.message, requestId: req.id, timestamp: new Date().toISOString(), stack: err.stack });

  const statusCode = err.status || 500;
  res.status(statusCode).json({
    error: {
      message: err.message,
      status: statusCode,
      requestId: req.id,
      stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
    },
  });
};

export class BaseError extends Error {
  public status: number;

  constructor(message: string, status: number = 500) {
    super(message);
    this.status = status;
    Object.setPrototypeOf(this, new.target.prototype); // restore prototype chain
  }
}

import { ObjectId } from 'mongodb';

export interface BaseDTO {
  id: ObjectId;
  createdAt: Date;
}

export class BaseMapper<TModel, TDTO extends BaseDTO> {
  toDTO(model: TModel): TDTO {
    throw new Error('Method not implemented.');
  }

  toModel(dto: TDTO): TModel {
    throw new Error('Method not implemented.');
  }
}

import winston from 'winston';

export const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'daily-reminder-system' },
  transports: [
    new winston.transports.Console({
      format: winston.format.simple(),
    }),
  ],
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple(),
  }));
}
